#!/usr/bin/perl

use strict;
use warnings;

use CGI;
use Storable qw(nstore retrieve);
use Fcntl qw(:flock); # For file locking

# --- Configuration ---
my $SESSION_DIR = "/tmp";
my $SESSION_COOKIE_NAME = "PERL_SESSION_ID";
my $SESSION_TIMEOUT_SECONDS = 3600; # 1 hour

# --- Global CGI object ---
my $q = CGI->new;

# --- Session Data Structure ---
# Sessions are stored as hashrefs:
# {
#   _id => "unique_session_id",
#   _created => timestamp,
#   _accessed => timestamp,
#   _data => { user_id => 123, username => "test", ... }
# }

# --- Function: generate_session_id ---
# Generates a unique session ID
sub generate_session_id {
    my $id = join '', map { chr(int(rand(26)) + (rand > 0.5 ? 65 : 97)) } 1..32;
    return $id;
}

# --- Function: get_session_file_path ---
# Returns the full path to a session file
sub get_session_file_path {
    my ($session_id) = @_;
    return "$SESSION_DIR/sess_$session_id";
}

# --- Function: load_session ---
# Loads session data from a file, or creates a new session
# Returns a hashref of session data
sub load_session {
    my $session_id = $q->cookie($SESSION_COOKIE_NAME);
    my $session_data;
    my $is_new_session = 0;

    if ($session_id) {
        my $session_file = get_session_file_path($session_id);

        # Attempt to open and lock the session file
        if (open my $fh, "+<", $session_file) {
            if (flock $fh, LOCK_EX) {
                # Check file size to avoid retrieving empty/corrupt files
                if (-s $session_file) {
                    eval {
                        $session_data = retrieve($fh);
                    };
                    if ($@) {
                        warn "Error retrieving session $session_id: $@. Creating new session.";
                        $session_data = undef; # Force new session creation
                    }
                }
                close $fh; # Release lock and close
            } else {
                warn "Could not lock session file $session_file. Creating new session.";
            }
        } else {
            # File doesn't exist or cannot be opened, create new session
            # warn "Session file $session_file not found or accessible. Creating new session.";
        }
    }

    # If session data is not loaded or is expired, create a new one
    if (!$session_data || (time - $session_data->{_accessed} > $SESSION_TIMEOUT_SECONDS)) {
        # If it was an existing session that expired, delete the old file
        if ($session_id && $session_data) {
            unlink get_session_file_path($session_id);
        }

        $session_id = generate_session_id();
        $session_data = {
            _id       => $session_id,
            _created  => time,
            _accessed => time,
            _data     => {}, # User-specific data goes here
        };
        $is_new_session = 1;
    }

    # Update access time for existing valid sessions
    $session_data->{_accessed} = time unless $is_new_session;

    # Set the session cookie if it's a new session or ID changed
    if ($is_new_session || $q->cookie($SESSION_COOKIE_NAME} ne $session_id) {
        print $q->header(
            -cookie => $q->cookie(
                -name    => $SESSION_COOKIE_NAME,
                -value   => $session_id,
                -expires => '+1y', # Long-lived cookie, session timeout handled by server
                -path    => '/',
                -httponly => 1,
                -secure  => 0, # Set to 1 for HTTPS only
            )
        );
    } else {
        # Print a regular header if no cookie change is needed
        print $q->header();
    }

    return $session_data;
}

# --- Function: save_session ---
# Saves session data to its file
sub save_session {
    my ($session_data) = @_;

    my $session_id = $session_data->{_id} or die "Session data missing _id";
    my $session_file = get_session_file_path($session_id);

    # Open file for writing, create if it doesn't exist
    # Use O_CREAT and O_TRUNC to ensure file is created/truncated
    if (open my $fh, ">", $session_file) {
        if (flock $fh, LOCK_EX) {
            nstore($session_data, $fh);
            close $fh; # Release lock and close
        } else {
            warn "Could not lock session file $session_file for writing.";
        }
    } else {
        warn "Could not open session file $session_file for writing: $!";
    }
}

# --- Function: delete_session ---
# Deletes a session file
sub delete_session {
    my ($session_id) = @_;
    my $session_file = get_session_file_path($session_id);
    unlink $session_file;
}

